#include <stdio.h>
int main() {
    int T, R, N, time, inconv, i, j;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &R, &N);
        int rooms[R];
        for (i = 0; i < R; i++) {
            rooms[i] = -1;
        }
        for (i = 0; i < N; i++) {
            scanf("%d %d", &time, &inconv);
            int room = time % R;
            int stay_time = 1;
            while (inconv > 0) {
                if (rooms[room] <= time) {
                    inconv--;
                    room = (room + 1) % R;
                } else {
                    room = (room + 1) % R;
                }
            }
            printf("%d %d\n", room, stay_time);
            rooms[room] = time + stay_time;
        }
    }
    return 0;
}

