        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int R = sc.nextInt();
            int N = sc.nextInt();
            int[] rooms = new int[R];
            for (int i = 0; i < R; i++) {
                rooms[i] = -1;
            }
            for (int i = 0; i < N; i++) {
                int time = sc.nextInt();
                int inconv = sc.nextInt();
                int room = time % R;
                int stay_time = 1;
                while (inconv > 0) {
                    if (rooms[room] <= time) {
                        inconv--;
                        room = (room + 1) % R;
                    } else {
                        room = (room + 1) % R;
                    }
                }
                System.out.println(room + " " + stay_time);
